**Lambda: Stuck Recovery**:
```typescript
const handler = async (event: { max_stuck_minutes: number }) => {
  const cutoff = new Date(Date.now() - event.max_stuck_minutes * 60 * 1000).toISOString();

  // Query for stuck records across all shards
  for (let shard = 0; shard < 10; shard++) {
    const params: QueryCommandInput = {
      TableName: 'fee_exemption_failures',
      IndexName: 'status-created_at-index',
      KeyConditionExpression: '#statusShard = :statusShard',
      FilterExpression: '#inProgressSince < :cutoff',
      ExpressionAttributeNames: {
        '#statusShard': 'status_shard',
        '#inProgressSince': 'in_progress_since'
      },
      ExpressionAttributeValues: marshall({
        ':statusShard': `IN_PROGRESS#${shard}`,
        ':cutoff': cutoff
      })
    };

    const result = await dynamodb.query(params);
    for (const item of result.Items || []) {
      const record = unmarshall(item);
      await resetToPendingRetry(record.cpf_token, record.created_at);
      logger.warn({ cpfToken: record.cpf_token }, 'Reset stuck IN_PROGRESS record');
    }
  }
};
```

